var rc = msg.responseCookies || {};
var names = Object.keys(rc);
if (names.length > 0) {
    var cookieStr = names.map(function(n){ return n + '=' + rc[n].value; }).join('; ');
    global.set('rws_cookie', cookieStr);
    node.status({fill:'green', shape:'dot', text:'Logged in'});
    msg.payload = { ok:true };
} else {
    node.status({fill:'yellow', shape:'ring', text:'No cookie'});
    msg.payload = { ok:false, error:'no cookie' };
}
return msg;

var cookie = global.get('rws_cookie');
if (!cookie) { node.warn('Not connected - run Connect first'); return null; }
msg.headers = { 'Accept': 'application/xhtml+xml;v=2.0', 'Cookie': cookie };
return msg;

function get(src, cls) {
    var m = src.match(new RegExp('class="' + cls + '">([^<]+)<'));
    return m ? m[1] : null;
}
var p = msg.payload;
var state = global.get('robot_data') || {};

if (get(p,'ctrlstate'))  state.ctrlstate  = get(p,'ctrlstate');
if (get(p,'opmode'))     state.opmode     = get(p,'opmode');
if (get(p,'speedratio')) state.speed      = get(p,'speedratio');
if (get(p,'ctrlexecstate')) state.rapid   = get(p,'ctrlexecstate');
if (get(p,'x')) {
    state.x = parseFloat(get(p,'x')).toFixed(1);
    state.y = parseFloat(get(p,'y')).toFixed(1);
    state.z = parseFloat(get(p,'z')).toFixed(1);
}
if (get(p,'rax_1')) {
    state.j1 = parseFloat(get(p,'rax_1')).toFixed(2);
    state.j2 = parseFloat(get(p,'rax_2')).toFixed(2);
    state.j3 = parseFloat(get(p,'rax_3')).toFixed(2);
    state.j4 = parseFloat(get(p,'rax_4')).toFixed(2);
    state.j5 = parseFloat(get(p,'rax_5')).toFixed(2);
    state.j6 = parseFloat(get(p,'rax_6')).toFixed(2);
}
state.updated = new Date().toLocaleTimeString();
global.set('robot_data', state);
msg.payload = state;
return msg;

var p = msg.payload || {};

// Go to a saved point: { goto:<id> }
if (p.goto) {
    var pts = global.get('points') || [];
    var pt = pts.filter(function(x){ return String(x.id) === String(p.goto); })[0];
    if (!pt) {
        msg.payload = { ok:false, error:'point not found: ' + p.goto };
        return [null, msg];
    }
    var gd = global.get('robot_data') || {};
    if (gd.ctrlstate && gd.ctrlstate !== 'motoron') {
        msg.payload = { ok:false, error:'controller not ready (state: ' + gd.ctrlstate + ')' };
        return [null, msg];
    }
    var t = pt.target;
    function r(v,d){ return Number(v).toFixed(d); }   // shorten: RAPID strings max 80 chars
    msg._cmd = 'GOTO' + [r(t.x,1),r(t.y,1),r(t.z,1),r(t.q1,4),r(t.q2,4),r(t.q3,4),r(t.q4,4),Math.round(t.cf1),Math.round(t.cf4),Math.round(t.cf6),Math.round(t.cfx)].join(';');
    msg.payload = msg._cmd + '\n';
    node.status({fill:'blue', shape:'dot', text:'GOTO ' + pt.name});
    return [msg, null];
}

// Jog: { jog:'X+'|'Y-'|'Z+'|'RX+'|'RY-'|'RZ+', step:<number> }
if (p.jog) {
    if (!/^R?[XYZ][+-]$/.test(p.jog) || isNaN(parseInt(p.step, 10))) {
        msg.payload = { ok:false, error:'bad jog: ' + p.jog + '/' + p.step };
        return [null, msg];
    }
    var rot = p.jog.charAt(0) === 'R';
    var step = Math.max(1, Math.min(rot ? 30 : 50, parseInt(p.step, 10)));  // clamp, mirrors RAPID
    var jd = global.get('robot_data') || {};
    if (jd.ctrlstate && jd.ctrlstate !== 'motoron') {
        msg.payload = { ok:false, error:'controller not ready (state: ' + jd.ctrlstate + ')' };
        return [null, msg];
    }
    msg._cmd = p.jog + step;
    msg.payload = msg._cmd + '\n';
    node.status({fill:'blue', shape:'dot', text:msg._cmd});
    return [msg, null];
}

// Named point: { routine: home|p1|p2|p3 }
var allowed = { home:'HOME', p1:'P1', p2:'P2', p3:'P3' };
var cmd = allowed[p.routine || ''];
if (!cmd) {
    msg.payload = { ok:false, error:'unknown routine: ' + (p.routine || '') };
    return [null, msg];
}
var data = global.get('robot_data') || {};
if (data.ctrlstate && data.ctrlstate !== 'motoron') {
    msg.payload = { ok:false, error:'controller not ready (state: ' + data.ctrlstate + ') - need Auto mode + Motors On' };
    return [null, msg];
}
msg._cmd = cmd;
msg.payload = cmd + '\n';
node.status({fill:'blue', shape:'dot', text:cmd});
return [msg, null];

var ack = (msg.payload || '').toString().trim();
var ok = ack.indexOf('OK:') === 0;
msg.payload = { ok:ok, routine: msg._cmd, ack:ack };
node.status({fill: ok ? 'green' : 'red', shape:'dot', text:ack || 'no ack'});
return msg;

var cookie = global.get('rws_cookie');
if (!cookie) {
    msg.payload = { ok:false, error:'not logged in to robot yet - run Connect first' };
    return [null, msg];
}
msg._name = ((msg.payload && msg.payload.name) || '').toString().trim();
msg.headers = { 'Accept':'application/xhtml+xml;v=2.0', 'Cookie':cookie };
msg.payload = '';
return [msg, null];

function g(cls){ var m = msg.payload.match(new RegExp('class="'+cls+'">([^<]+)<')); return m ? parseFloat(m[1]) : null; }
var t = { x:g('x'),y:g('y'),z:g('z'),q1:g('q1'),q2:g('q2'),q3:g('q3'),q4:g('q4'),cf1:g('cf1'),cf4:g('cf4'),cf6:g('cf6'),cfx:g('cfx') };
if (t.x === null || t.q1 === null) {
    msg.payload = { ok:false, error:'could not read robot pose' };
    return [msg, null];
}
var pts = global.get('points') || [];
var name = msg._name;
if (!name) { var k = 1; while (pts.some(function(p){ return p.name === 'Point ' + k; })) k++; name = 'Point ' + k; }
var pt = { id: 'p' + Date.now(), name: name, target: t };
pts.push(pt);
global.set('points', pts);
msg.payload = { ok:true, name:name, points:pts };
return [msg, { payload: JSON.stringify(pts) }];

var rc = msg.responseCookies || {};
var names = Object.keys(rc);
if (names.length > 0) {
    global.set('rws_cookie', names.map(function(n){ return n + '=' + rc[n].value; }).join('; '));
    node.status({fill:'green', shape:'dot', text:'Logged in'});
    msg.payload = { ok:true };
} else {
    node.status({fill:'yellow', shape:'ring', text:'No cookie'});
    msg.payload = { ok:false, error:'no cookie' };
}
return msg;

var cookie = global.get('rws_cookie');
if (!cookie) { node.warn('Not connected - run Connect first'); return null; }
msg.headers = { 'Accept': 'application/xhtml+xml;v=2.0', 'Cookie': cookie };
return msg;

function get(src, cls){ var m = src.match(new RegExp('class="' + cls + '">([^<]+)<')); return m ? m[1] : null; }
var p = msg.payload;
var s = global.get('robot_data') || {};
if (get(p,'ctrlstate'))     s.ctrlstate = get(p,'ctrlstate');
if (get(p,'opmode'))        s.opmode    = get(p,'opmode');
if (get(p,'speedratio'))    s.speed     = get(p,'speedratio');
if (get(p,'ctrlexecstate')) s.rapid     = get(p,'ctrlexecstate');
if (get(p,'x')) { s.x = parseFloat(get(p,'x')).toFixed(1); s.y = parseFloat(get(p,'y')).toFixed(1); s.z = parseFloat(get(p,'z')).toFixed(1); }
if (get(p,'rax_1')) { for (var i=1;i<=6;i++){ s['j'+i] = parseFloat(get(p,'rax_'+i)).toFixed(2); } }
s.updated = new Date().toLocaleTimeString();
global.set('robot_data', s);
msg.payload = s;
return msg;

var p = msg.payload || {};
function ready(){ var d = global.get('robot_data') || {}; return !d.ctrlstate || d.ctrlstate === 'motoron'; }
function blocked(){ var d = global.get('robot_data') || {}; return { ok:false, error:'controller not ready (state: ' + d.ctrlstate + ')' }; }
function send(cmd){ msg._cmd = cmd; msg.payload = cmd + '\n'; node.status({fill:'blue', shape:'dot', text:cmd}); return [msg, null]; }
function fail(e){ msg.payload = { ok:false, error:e }; return [null, msg]; }

// goto saved point
if (p.goto) {
    var pt = (global.get('points') || []).filter(function(x){ return String(x.id) === String(p.goto); })[0];
    if (!pt) return fail('point not found: ' + p.goto);
    if (!ready()) return [null, Object.assign(msg,{payload:blocked()})];
    var t = pt.target;
    function r(v,d){ return Number(v).toFixed(d); }
    return send('GOTO' + [r(t.x,1),r(t.y,1),r(t.z,1),r(t.q1,4),r(t.q2,4),r(t.q3,4),r(t.q4,4),Math.round(t.cf1),Math.round(t.cf4),Math.round(t.cf6),Math.round(t.cfx)].join(';'));
}
