if (p.jog) {
    if (!/^R?[XYZ][+-]$/.test(p.jog) || isNaN(parseInt(p.step,10))) return fail('bad jog: ' + p.jog + '/' + p.step);
    if (!ready()) return [null, Object.assign(msg,{payload:blocked()})];
    var rot = p.jog.charAt(0) === 'R';
    return send(p.jog + Math.max(1, Math.min(rot ? 30 : 50, parseInt(p.step,10))));
}
// joint jog
if (p.joint) {
    if (!/^J[1-6][+-]$/.test(p.joint) || isNaN(parseInt(p.step,10))) return fail('bad joint: ' + p.joint + '/' + p.step);
    if (!ready()) return [null, Object.assign(msg,{payload:blocked()})];
    return send(p.joint + Math.max(1, Math.min(30, parseInt(p.step,10))));
}
// speed override (no guard)
if (p.speed !== undefined) {
    var sp = parseInt(p.speed,10);
    if (isNaN(sp)) return fail('bad speed: ' + p.speed);
    return send('SPEED' + Math.max(1, Math.min(100, sp)));
}
// set home (no guard)
if (p.sethome) return send('SETHOME');
// named point
var allowed = { home:'HOME', p1:'P1', p2:'P2', p3:'P3' };
var cmd = allowed[p.routine || ''];
if (!cmd) return fail('unknown command: ' + JSON.stringify(p));
if (!ready()) return [null, Object.assign(msg,{payload:blocked()})];
return send(cmd);

var ack = (msg.payload || '').toString().trim();
var ok = ack.indexOf('OK:') === 0;
msg.payload = { ok:ok, cmd: msg._cmd, ack:ack };
node.status({fill: ok ? 'green' : 'red', shape:'dot', text:ack || 'no ack'});
return msg;

var cookie = global.get('rws_cookie');
var state = msg.payload && msg.payload.state;
if (state !== 'motoron' && state !== 'motoroff') { msg.payload = { ok:false, error:'bad state: ' + state }; return [null, msg]; }
if (!cookie) { msg.payload = { ok:false, error:'not logged in - run Connect first' }; return [null, msg]; }
msg.headers = { 'Accept':'application/xhtml+xml;v=2.0', 'Content-Type':'application/x-www-form-urlencoded;v=2.0', 'Cookie':cookie };
msg.payload = 'ctrl-state=' + state;
return [msg, null];

var code = msg.statusCode || 0;
var ok = code >= 200 && code < 300;
node.status({fill: ok ? 'green' : 'red', shape:'dot', text:'ctrl-state ' + code});
msg.payload = { ok:ok, status:code };
return msg;

var cookie = global.get('rws_cookie');
if (!cookie) { msg.payload = { ok:false, error:'not logged in - run Connect first' }; return [null, msg]; }
msg._name = ((msg.payload && msg.payload.name) || '').toString().trim();
msg.headers = { 'Accept':'application/xhtml+xml;v=2.0', 'Cookie':cookie };
