var t = { x:g('x'),y:g('y'),z:g('z'),q1:g('q1'),q2:g('q2'),q3:g('q3'),q4:g('q4'),cf1:g('cf1'),cf4:g('cf4'),cf6:g('cf6'),cfx:g('cfx') };
if (t.x === null || t.q1 === null) { msg.payload = { ok:false, error:'could not read robot pose' }; return [msg, null]; }
var pts = global.get('points') || [];
var name = msg._name;
if (!name) { var k = 1; while (pts.some(function(p){ return p.name === 'Point ' + k; })) k++; name = 'Point ' + k; }
pts.push({ id:'p' + Date.now(), name:name, target:t });
global.set('points', pts);
msg.payload = { ok:true, name:name, points:pts };
return [msg, { payload: JSON.stringify(pts) }];

var id = msg.payload && msg.payload.id;
var pts = (global.get('points') || []).filter(function(p){ return String(p.id) !== String(id); });
global.set('points', pts);
msg.payload = { ok:true, points:pts };
return [msg, { payload: JSON.stringify(pts) }];

var p = msg.payload || {};
var ids = Array.isArray(p.ids) ? p.ids : [];
var pts = global.get('points') || [];
function r(v,d){ return Number(v).toFixed(d); }
var cmds = [];
ids.forEach(function(id){
    var pt = pts.filter(function(x){ return String(x.id) === String(id); })[0];
    if (pt) { var t = pt.target; cmds.push('GOTO' + [r(t.x,1),r(t.y,1),r(t.z,1),r(t.q1,4),r(t.q2,4),r(t.q3,4),r(t.q4,4),Math.round(t.cf1),Math.round(t.cf4),Math.round(t.cf6),Math.round(t.cfx)].join(';')); }
});
if (!cmds.length) { return [{ payload:{ ok:false, error:'no valid points' } }, null]; }
var gd = global.get('robot_data') || {};
if (gd.ctrlstate && gd.ctrlstate !== 'motoron') { return [{ payload:{ ok:false, error:'controller not ready (state: ' + gd.ctrlstate + ')' } }, null]; }
if (p.mode === 'pingpong' && cmds.length > 1) { cmds = cmds.concat(cmds.slice(0, -1).reverse()); }
global.set('seq_loop', !!p.loop);
global.set('seq_cmds', cmds);
global.set('seq_dwell', Math.max(0, parseInt(p.dwell,10) || 0));
global.set('seq_idx', 0);
global.set('seq_running', true);
return [{ payload:{ ok:true, count:cmds.length } }, { _seq:true }];

if (!global.get('seq_running')) { node.status({fill:'grey', shape:'ring', text:'idle'}); return null; }
var cmds = global.get('seq_cmds') || [];
var idx = global.get('seq_idx') || 0;
if (idx >= cmds.length) {
    if (!global.get('seq_loop')) { global.set('seq_running', false); node.status({fill:'green', shape:'dot', text:'done'}); return null; }
    idx = 0;
}
global.set('seq_idx', idx + 1);
node.status({fill:'blue', shape:'dot', text:'seq ' + (idx + 1) + '/' + cmds.length});
return { payload: cmds[idx] + '\n', _seqdwell: global.get('seq_dwell') || 0 };

global.set('seq_running', false);
node.status({fill:'yellow', shape:'ring', text:'stopped'});
msg.payload = { ok:true };
return msg;

