  .led.yellow { background: #d29922; box-shadow: 0 0 8px #d29922; }
  .led.red    { background: #f85149; box-shadow: 0 0 8px #f85149; }
  .led.grey   { background: #484f58; }
  .bar-wrap { flex: 1; margin: 0 12px; background: #21262d; border-radius: 4px; height: 8px; overflow: hidden; }
  .bar { height: 100%; background: #ff6b00; border-radius: 4px; transition: width 0.5s; }
  .joint-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; }
  .joint { background: #0d1117; border-radius: 8px; padding: 12px; text-align: center; }
  .joint .jname { font-size: 0.7rem; color: #8b949e; text-transform: uppercase; margin-bottom: 4px; }
  .joint .jval { font-size: 1.2rem; font-weight: 700; color: #ff6b00; font-family: monospace; }
  .joint .jdeg { font-size: 0.7rem; color: #8b949e; }
  .updated { color: #484f58; font-size: 0.75rem; text-align: right; margin-top: 16px; }
  .connecting { color: #8b949e; font-style: italic; }
  .controls { display: flex; gap: 12px; flex-wrap: wrap; }
  .btn { flex: 1; min-width: 120px; padding: 16px; border: none; border-radius: 8px; background: #ff6b00; color: #fff; font-size: 0.95rem; font-weight: 600; cursor: pointer; transition: background 0.2s, transform 0.1s; }
  .btn:hover { background: #ff8528; }
  .btn:active { transform: translateY(1px); }
  .btn:disabled { opacity: 0.5; cursor: wait; }
  .btn.home { background: #3fb950; }
  .btn.home:hover { background: #4cc85e; }
  .jog-steps { display:flex; gap:18px; align-items:center; flex-wrap:wrap; margin-bottom:14px; color:#8b949e; font-size:0.85rem; }
  .jog-steps input[type=number] { width:64px; background:#0d1117; color:#e6edf3; border:1px solid #30363d; border-radius:6px; padding:6px; }
  .jog-grid { display:grid; grid-template-columns: repeat(6, 1fr); gap:10px; }
  .btn.jog { background:#1f6feb; padding:14px 6px; font-size:0.8rem; }
  .btn.jog:hover { background:#388bfd; }
  .btn.jog.rot { background:#8957e5; }
  .btn.jog.rot:hover { background:#9e6bf0; }
  @media (max-width: 700px) { .jog-grid { grid-template-columns: repeat(2, 1fr); } }
  .pt-row { display:flex; gap:10px; align-items:center; margin-bottom:10px; flex-wrap:wrap; }
  .pt-row input[type=text], .pt-row select { flex:1; min-width:140px; background:#0d1117; color:#e6edf3; border:1px solid #30363d; border-radius:6px; padding:10px; font-size:0.9rem; }
  .pt-row .btn { flex:0 0 auto; min-width:90px; }
  .btn.del { background:#da3633; }
  .btn.del:hover { background:#f85149; }
  .btn.stop { background:#da3633; }
  .btn.stop:hover { background:#f85149; }
  .btn.recover { background:#1f6feb; }
  .btn.recover:hover { background:#388bfd; }
  .seq-list { list-style:none; margin:8px 0; padding:0; }
  .seq-list li { display:flex; align-items:center; gap:10px; background:#0d1117; border:1px solid #30363d; border-radius:8px; padding:8px 12px; margin-bottom:6px; }
  .seq-list .sidx { color:#8b949e; width:1.6em; text-align:right; font-family:monospace; }
  .seq-list .sname { flex:1; font-family:monospace; }
  .seq-list button { background:#21262d; color:#e6edf3; border:1px solid #30363d; border-radius:6px; padding:4px 10px; cursor:pointer; }
  .seq-list button:hover:not(:disabled) { background:#30363d; }
  .seq-list button:disabled { opacity:0.3; cursor:default; }
  .seq-list .x { color:#f85149; }
  .seq-list .empty { color:#484f58; font-style:italic; }
  .toast { margin-top: 14px; font-size: 0.85rem; color: #8b949e; min-height: 1.2em; font-family: monospace; }
</style>
</head>
<body>
<h1>ABB-GoFa-12</h1>
<p class="subtitle">Live robot status &mdash; updates ~5 times per second</p>
<div class="layout">
    <div class="column">
      <div class="card">
          <h2>Controller Status</h2>
          <div class="row">
            <span class="label">State</span>
            <span class="value"><span class="led grey" id="led"></span><span id="ctrlstate">...</span></span>
          </div>
          <div class="row">
            <span class="label">Mode</span>
            <span class="value" id="opmode">...</span>
          </div>
          <div class="row">
            <span class="label">RAPID</span>
            <span class="value" id="rapid">...</span>
          </div>
          <div class="row">
            <span class="label">Speed</span>
            <div class="bar-wrap"><div class="bar" id="speedbar" style="width:0%"></div></div>
            <span class="value" id="speed">...</span>
          </div>
        </div>
      <div class="card">
          <h2>Tool Position (mm)</h2>
          <div class="row"><span class="label">X</span><span class="value" id="px">...</span></div>
          <div class="row"><span class="label">Y</span><span class="value" id="py">...</span></div>
          <div class="row"><span class="label">Z</span><span class="value" id="pz">...</span></div>
        </div>
      <div class="card">
          <h2>Joint Angles (degrees)</h2>
          <div class="joint-grid">
            <div class="joint"><div class="jname">J1</div><div class="jval" id="j1">...</div><div class="jdeg">deg</div></div>
            <div class="joint"><div class="jname">J2</div><div class="jval" id="j2">...</div><div class="jdeg">deg</div></div>
            <div class="joint"><div class="jname">J3</div><div class="jval" id="j3">...</div><div class="jdeg">deg</div></div>
            <div class="joint"><div class="jname">J4</div><div class="jval" id="j4">...</div><div class="jdeg">deg</div></div>
            <div class="joint"><div class="jname">J5</div><div class="jval" id="j5">...</div><div class="jdeg">deg</div></div>
            <div class="joint"><div class="jname">J6</div><div class="jval" id="j6">...</div><div class="jdeg">deg</div></div>
          </div>
        </div>
    </div>
    <div class="column">
      <div class="card">
          <h2>Robot Control</h2>
          <div class="controls">
            <button class="btn home" id="btn-home" onclick="move('home')">Home</button>
            <button class="btn" onclick="setHome()">Set Home (here)</button>
            <button class="btn stop" onclick="ctrl('motoroff')">Motors Off</button>
            <button class="btn recover" onclick="ctrl('motoron')">Motors On</button>
          </div>
          <div class="toast" id="toast">Ready.</div>
        </div>
      <div class="card">
          <h2>Jog &mdash; move (base frame) &amp; rotate (tool frame)</h2>
          <div class="jog-steps">
            <label>Step <span id="lin-cm">2</span> cm
              <input type="range" id="lin-range" min="1" max="5" step="1" value="2" oninput="syncLin('range')"></label>
            <label>or mm <input type="number" id="lin-mm" min="1" max="50" value="20" oninput="syncLin('mm')"></label>
            <label>Angle <input type="number" id="ang-deg" min="1" max="30" value="5"> deg</label>
          </div>
          <div class="jog-grid">
            <button class="btn jog" onclick="jog('Y+')">Right +Y</button>
            <button class="btn jog" onclick="jog('Y-')">Left -Y</button>
            <button class="btn jog" onclick="jog('X-')">Back -X</button>
            <button class="btn jog" onclick="jog('X+')">Forward +X</button>
            <button class="btn jog" onclick="jog('Z+')">Up +Z</button>
            <button class="btn jog" onclick="jog('Z-')">Down -Z</button>
            <button class="btn jog rot" onclick="jog('RX+')">Roll +</button>
            <button class="btn jog rot" onclick="jog('RX-')">Roll -</button>
            <button class="btn jog rot" onclick="jog('RY+')">Pitch +</button>
            <button class="btn jog rot" onclick="jog('RY-')">Pitch -</button>
            <button class="btn jog rot" onclick="jog('RZ+')">Yaw +</button>
            <button class="btn jog rot" onclick="jog('RZ-')">Yaw -</button>
          </div>
        </div>
      <div class="card">
          <h2>Joint Jog (per-axis, degrees)</h2>
          <div class="jog-steps">
            <label>Angle <input type="number" id="joint-deg" min="1" max="30" value="5"> deg</label>
          </div>
          <div class="jog-grid">
            <button class="btn jog rot" onclick="jogJoint('J1+')">J1 +</button>
            <button class="btn jog rot" onclick="jogJoint('J1-')">J1 -</button>
            <button class="btn jog rot" onclick="jogJoint('J2+')">J2 +</button>
            <button class="btn jog rot" onclick="jogJoint('J2-')">J2 -</button>
            <button class="btn jog rot" onclick="jogJoint('J3+')">J3 +</button>
            <button class="btn jog rot" onclick="jogJoint('J3-')">J3 -</button>
            <button class="btn jog rot" onclick="jogJoint('J4+')">J4 +</button>
            <button class="btn jog rot" onclick="jogJoint('J4-')">J4 -</button>
            <button class="btn jog rot" onclick="jogJoint('J5+')">J5 +</button>
            <button class="btn jog rot" onclick="jogJoint('J5-')">J5 -</button>
            <button class="btn jog rot" onclick="jogJoint('J6+')">J6 +</button>
            <button class="btn jog rot" onclick="jogJoint('J6-')">J6 -</button>
          </div>
        </div>
      <div class="card">
          <h2>Saved Points</h2>
          <div class="pt-row">
            <input type="text" id="ptname" placeholder="point name (optional)">
            <button class="btn home" onclick="savePoint()">Save current pose</button>
          </div>
          <div class="pt-row">
            <select id="pointsel"></select>
            <button class="btn" onclick="goPoint()">Go</button>
            <button class="btn del" onclick="deletePoint()">Delete</button>
          </div>
        </div>
      <div class="card">
          <h2>Sequence Runner</h2>
          <div class="pt-row">
            <select id="seqadd"></select>
            <button class="btn" onclick="addSeqStep()">Add step</button>
            <label style="color:#8b949e; font-size:0.85rem;">Pause <input type="number" id="seq-dwell" min="0" max="10000" value="800" style="width:80px; background:#0d1117; color:#e6edf3; border:1px solid #30363d; border-radius:6px; padding:6px;"> ms</label>
            <button class="btn home" onclick="runSeq()">Run</button>
            <button class="btn del" onclick="stopSeq()">Stop</button>
            <label style="color:#8b949e; font-size:0.85rem; display:flex; align-items:center; gap:6px;"><input type="checkbox" id="seq-loop"> Loop</label>
            <label style="color:#8b949e; font-size:0.85rem; display:flex; align-items:center; gap:6px;"><input type="checkbox" id="seq-pingpong"> Back-and-forth (reverse on return)</label>
          </div>
          <ol id="seqlist" class="seq-list"></ol>
          <p style="color:#8b949e; font-size:0.8rem;">Add points to build the order, reorder with the arrows, remove with X. A point may appear more than once.</p>
        </div>
    </div>
  </div>
<p class="updated" id="updated">Connecting...</p>

<script>
function renderPoints(points) {
  var sel = document.getElementById('pointsel');
  if (!sel) return;
  var cur = sel.value;
  sel.innerHTML = '';
  points.forEach(function(p){ var o = document.createElement('option'); o.value = p.id; o.textContent = p.name; sel.appendChild(o); });
  if (cur) sel.value = cur;
  var add = document.getElementById('seqadd');
  if (add) {
    var curAdd = add.value;
    add.innerHTML = '';
    points.forEach(function(p){ var o = document.createElement('option'); o.value = p.id; o.textContent = p.name; add.appendChild(o); });
    if (curAdd) add.value = curAdd;
  }
  renderSeq();
}
function goPoint() {
  var sel = document.getElementById('pointsel');
  if (!sel || !sel.value) return;
  sendMove({ goto: sel.value }, 'Go ' + sel.options[sel.selectedIndex].text);
}
function savePoint() {
  var name = (document.getElementById('ptname').value || '').trim();
  var toast = document.getElementById('toast');
  toast.style.color = '#8b949e'; toast.textContent = 'Saving point...';
  fetch('/robot/savepoint', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ name:name }) })
    .then(function(r){ return r.json(); })
    .then(function(res){
      if (res.ok) { toast.style.color='#3fb950'; toast.textContent='Saved: ' + res.name; document.getElementById('ptname').value=''; renderPoints(res.points||[]); }
      else { toast.style.color='#f85149'; toast.textContent='Error: ' + (res.error||'failed'); }
    })
    .catch(function(){ toast.style.color='#f85149'; toast.textContent='Connection error'; });
}
function deletePoint() {
  var sel = document.getElementById('pointsel');
  if (!sel || !sel.value) return;
  var toast = document.getElementById('toast');
  toast.style.color='#8b949e'; toast.textContent='Deleting...';
  fetch('/robot/deletepoint', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ id: sel.value }) })
    .then(function(r){ return r.json(); })
    .then(function(res){ if(res.ok){ toast.style.color='#3fb950'; toast.textContent='Deleted'; renderPoints(res.points||[]); } else { toast.style.color='#f85149'; toast.textContent='Error'; } })
    .catch(function(){ toast.style.color='#f85149'; toast.textContent='Connection error'; });
}
function ctrl(state) {
  var toast = document.getElementById('toast');
  toast.style.color = '#8b949e'; toast.textContent = (state === 'motoroff' ? 'Stopping...' : 'Recovering...');
  fetch('/robot/ctrlstate', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ state:state }) })
    .then(function(r){ return r.json(); })
    .then(function(res){ toast.style.color = res.ok ? '#3fb950' : '#f85149'; toast.textContent = res.ok ? (state === 'motoroff' ? 'Motors OFF' : 'Motors ON') : ('Error: ' + (res.error || res.status)); })
    .catch(function(){ toast.style.color = '#f85149'; toast.textContent = 'Connection error'; });
}
function jogJoint(tok) {
  var step = parseInt(document.getElementById('joint-deg').value) || 5;
  sendMove({ joint: tok, step: step }, 'Joint ' + tok + ' ' + step + 'deg');
}
function setHome() {
  if (!confirm('Set HOME to the current pose? (saved on the controller)')) return;
  sendMove({ sethome: true }, 'Set Home');
}
var seqSteps = [];
function renderSeq() {
  var list = document.getElementById('seqlist');
  if (!list) return;
  list.innerHTML = '';
  if (!seqSteps.length) { var li = document.createElement('li'); li.className = 'empty'; li.textContent = 'No steps yet \u2014 add points above.'; list.appendChild(li); return; }
  seqSteps.forEach(function(s, i){
    var li = document.createElement('li');
    li.innerHTML = '<span class="sidx">' + (i + 1) + '</span><span class="sname">' + s.name + '</span>' +
      '<button onclick="seqUp(' + i + ')"' + (i === 0 ? ' disabled' : '') + '>&#9650;</button>' +
      '<button onclick="seqDown(' + i + ')"' + (i === seqSteps.length - 1 ? ' disabled' : '') + '>&#9660;</button>' +
      '<button class="x" onclick="seqDel(' + i + ')">&times;</button>';
    list.appendChild(li);
  });
}
function addSeqStep() {
  var sel = document.getElementById('seqadd');
  if (!sel || !sel.value) return;
  seqSteps.push({ id: sel.value, name: sel.options[sel.selectedIndex].text });
  renderSeq();
}
function seqUp(i)   { if (i <= 0) return; var t = seqSteps[i-1]; seqSteps[i-1] = seqSteps[i]; seqSteps[i] = t; renderSeq(); }
function seqDown(i) { if (i >= seqSteps.length - 1) return; var t = seqSteps[i+1]; seqSteps[i+1] = seqSteps[i]; seqSteps[i] = t; renderSeq(); }
function seqDel(i)  { seqSteps.splice(i, 1); renderSeq(); }
function runSeq() {
  var steps = seqSteps.map(function(s){ return { name: s.name }; });
  if (!steps.length) return;
  var dwell = parseInt(document.getElementById('seq-dwell').value) || 0;
  var loop = document.getElementById('seq-loop').checked;
  var pingpong = document.getElementById('seq-pingpong').checked;
  var toast = document.getElementById('toast');
  toast.style.color = '#8b949e'; toast.textContent = 'Running sequence (' + steps.length + ')...';
  fetch('/robot/sequence', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ steps:steps, dwell:dwell, loop:loop, pingpong:pingpong }) })
    .then(function(r){ return r.json(); })
    .then(function(res){ toast.style.color = res.ok ? '#3fb950' : '#f85149'; toast.textContent = res.ok ? ('Sequence started: ' + res.count + ' points') : ('Error: ' + (res.error || 'failed')); })
    .catch(function(){ toast.style.color = '#f85149'; toast.textContent = 'Connection error'; });
}
function stopSeq() {
  fetch('/robot/sequence/stop', { method:'POST' })
    .then(function(r){ return r.json(); })
    .then(function(){ var t = document.getElementById('toast'); t.style.color = '#d29922'; t.textContent = 'Sequence stop requested'; });
}
function update() {
  fetch('/robot/data')
    .then(r => r.json())
    .then(d => {
      document.getElementById('ctrlstate').textContent = d.ctrlstate || '-';
      document.getElementById('opmode').textContent = d.opmode || '-';
      document.getElementById('rapid').textContent = d.rapid || '-';
      document.getElementById('speed').textContent = (d.speed || '0') + '%';
      document.getElementById('speedbar').style.width = (d.speed || 0) + '%';
      var fmt=function(v){return v!=null&&v!==''?(+v).toFixed(2):'-';};
      document.getElementById('px').textContent = fmt(d.x);
      document.getElementById('py').textContent = fmt(d.y);
      document.getElementById('pz').textContent = fmt(d.z);
      document.getElementById('j1').textContent = fmt(d.j1);
      document.getElementById('j2').textContent = fmt(d.j2);
      document.getElementById('j3').textContent = fmt(d.j3);
      document.getElementById('j4').textContent = fmt(d.j4);
      document.getElementById('j5').textContent = fmt(d.j5);
      document.getElementById('j6').textContent = fmt(d.j6);
      document.getElementById('updated').textContent = 'Last update: ' + d.updated;
      renderPoints(d.points || []);
      var led = document.getElementById('led');
      var colors = { motoron:'green', guardstop:'yellow', emergencystop:'red', sysfail:'red' };
      led.className = 'led ' + (colors[d.ctrlstate] || 'grey');
    })
    .catch(function() {
      document.getElementById('updated').textContent = 'Connection error — retrying...';
    });
}
function sendMove(body, label) {
  var toast = document.getElementById('toast');
  var btns = document.querySelectorAll('.btn');
  btns.forEach(function(b){ b.disabled = true; });
  toast.style.color = '#8b949e';
  toast.textContent = 'Sending ' + label + '...';
  fetch('/robot/move', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(body) })
    .then(function(r){ return r.json(); })
    .then(function(res){
      if (res.ok) { toast.style.color = '#3fb950'; toast.textContent = 'OK: ' + label + (res.ack ? ' (' + res.ack + ')' : ''); }
      else { toast.style.color = '#f85149'; toast.textContent = 'Error: ' + (res.error || 'failed'); }
    })
    .catch(function(){ toast.style.color = '#f85149'; toast.textContent = 'Connection error'; })
    .finally(function(){ btns.forEach(function(b){ b.disabled = false; }); });
}
function move(key) {
  var names = { home:'Home', p1:'Point 1', p2:'Point 2', p3:'Point 3' };
  sendMove({ routine:key }, names[key] || key);
}
function jog(token) {
  var rot = token.charAt(0) === 'R';
  var step = rot ? (parseInt(document.getElementById('ang-deg').value) || 5)
                 : (parseInt(document.getElementById('lin-mm').value) || 10);
  sendMove({ jog:token, step:step }, 'Jog ' + token + ' ' + step + (rot ? 'deg' : 'mm'));
}
function syncLin(src) {
  var r = document.getElementById('lin-range'), mm = document.getElementById('lin-mm');
  if (src === 'range') { mm.value = r.value * 10; }
  else { var v = Math.max(1, Math.min(50, parseInt(mm.value) || 10)); mm.value = v; r.value = Math.round(v / 10) || 1; }
  document.getElementById('lin-cm').textContent = (mm.value / 10);
}
update();
setInterval(update, 200);
</script>
</body>
</html>`;
return msg;

var d = flow.get('robot_data') || {};
msg.payload = Object.assign({}, d, { points: msg.payload });
msg.statusCode = 200;
return msg;

var p = msg.payload || {};
if (p.routine || p.sethome) {
    msg.payload = { command: p.sethome ? 'SETHOME' : p.routine.toUpperCase() };
    return [msg, null, null, null, null];
}
if (p.jog) {
    msg.payload = { axis: p.jog.slice(0,-1), dir: p.jog.slice(-1), step: p.step };
    return [null, msg, null, null, null];
}
if (p.joint) {
    msg.payload = { joint: p.joint.slice(0,-1), dir: p.joint.slice(-1), step: p.step };
    return [null, null, msg, null, null];
}
if (p.goto) {
    msg.payload = { name: p.goto, id: p.goto };
    return [null, null, null, msg, null];
}
msg.statusCode = 400;
msg.payload = { ok: false, error: 'unknown command' };
return [null, null, null, null, msg];

msg.payload.name = msg.payload.point ? msg.payload.point.name : '';
msg.statusCode = 200;
return msg;

var p = msg.payload || {};
var steps = p.steps || [];
// immediate HTTP reply
var reply = { req: msg.req, res: msg.res,
    statusCode: 200, payload: { ok: true, count: steps.length } };
// sequencer message with runtime overrides
msg.payload = {
    steps:    steps,
    dwell:    p.dwell    != null ? p.dwell    : 800,
    loop:     p.loop     != null ? p.loop     : false,
    pingpong: p.pingpong != null ? p.pingpong : false
};
return [reply, msg];
